import pytest
import requests

@pytest.mark.parametrize("payload,label", [
    ({"resourceType": "Patient", "name": [{"family": "Doe"}], "birthDate": "1970-01-01"}, "missing gender"),
    ({"resourceType": "Patient", "name": [{"family": "Doe"}], "gender": "male"}, "missing birthDate"),
    ({"resourceType": "Patient", "gender": "female"}, "missing name and birthDate"),
    ({"resourceType": "Patient"}, "missing all mandatory fields"),
])
def test_create_patient_multiple_missing_fields_decision_table(
    payload, label, clinician_auth_headers, base_url
):
    resp = requests.post(
        f"{base_url}/Patient",
        json=payload,
        headers=clinician_auth_headers
    )
    assert resp.status_code == 422, (
        f"[{label}] Expected 422, got {resp.status_code}"
    )
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome", (
        f"[{label}] Expected OperationOutcome"
    )
